use strict;
use warnings;
use CAM::PDF;

# Path to the PDF file
my $pdf_file = 'path/to/your/pdffile.pdf';

# Open the PDF file
my $pdf = CAM::PDF->new($pdf_file);

# Check if the PDF file was opened successfully
