        if ($line =~ /\b\d+\.\d+\.\d+\b/) {  # Simple regex to find dates
            print "Date found: $line\n";
        }
        if ($line =~ /\b[A-Z][a-z]+(?: [A-Z][a-z]+)+\b/) {  # Simple regex to find names
